<template>

	<view class="fullBody">
		<!-- <view class="">
			<view class="">
				<view class="navitionBar hasBg andNav">
					<view class="backArea" @click="$util.back()">
						<image class="headerBack"
							src="data:image/png;base64,"
							mode="aspectFit"></image>

					</view>

					<view class="navTitle">关键字搜索</view>
				</view>
			</view>
		</view> -->
		<view class="searchWrap">
			<view class="inputWrap">
				<view class="iconWrap search">
					<image class="img" 
						:src="$util.img('/statics/uni/img/search/search.png')"
						mode="aspectFit"></image>
				</view>
				<input type="text" focus v-model="keyword" confirm-type="search" @search="search" @custom="search" @input="onKeyInput" maxlength="140"
					:placeholder="placeholder" class="inputText">
				<view class="iconWrap clear" v-if="keyword !=''" @click="keyword = '',query_list=[]">
					<image class="img" 
						:src="$util.img('/statics/uni/img/search/close.png')"
						mode="aspectFit"></image>
				</view>
			</view>
			<view class="searchTxt" @click="search">搜索</view>
		</view>

		<scroll-view class="flexScroll" scroll-y="true">
			<view>
				<view class="searchTip" v-if="query_list.length > 0">
					<view class="tipWrap">
						<view class="tip" @click="search($event,item.goods_name)" v-for="(item,index) in query_list" :key="index">({{item.goods_price}}){{item.goods_name}}</view>
					</view>
				</view>
				<view v-if="query_list.length == 0">
					<view class="searchWords">
						<view class="tit">历史搜索<view class="clear" @click="delAll">
								<image class="img" 
									:src="$util.img('/statics/uni/img/search/del.png')"
									mode="aspectFit"></image>
							</view>
						</view>
						<view class="wordWrap">
							<view v-for="(item,index) in history_list" :key="index" @click="search($event,item)"
								class="word">{{item}}
							</view>
						</view>
					</view>
					<view class="searchWords">
						<view class="tit">热门搜索</view>
						<view class="wordWrap">
							<view v-for="(item,index) in hot_list" :key="index" class="word"
								@click="search($event,item.word)" :style="'color:'+item.fontcolor">{{item.word}}
								<view v-if="item.ishot == 1" class="iconTag">
									<image class="img" 
										:src="$util.img('/statics/uni/img/index/hot.png')">
									</image>
								</view>
							</view>
						</view>
					</view>
				</view>
			</view>
		</scroll-view>

	</view>
</template>

<script>
	export default {
		data() {
			return {
				keyword: '',
				placeholder: '',
				history_list: [],
				hot_list: [],
				query_list: [],
				search_history_key: 'fonnie_search_history',
				search_placeholder_key: 'fonnie_search_placeholder',
			}
		},
		onShow() {
			let that = this
			//历史搜索列表
			uni.getStorage({
				key: this.search_history_key,
				success: (res) => {
					that.history_list = JSON.parse(res.data);
				}
			});
			//提示关键字
			uni.getStorage({
				key: this.search_placeholder_key,
				success: (res) => {
					that.placeholder = res.data;
				}
			});

			//热门搜索	
			this.$u.api.searchKey({}).then(res => {
		
				this.hot_list = res
				if (this.placeholder == '' && res.length > 0) {
					this.placeholder = res[0].word
				}
			}).catch(res => {})
		},
		methods: {
			//删除所有
			delAll() {
				var that = this
				uni.showModal({
					title: '提示',
					content: '确定全部删除',
					success(res) {
						if (res.confirm) {
							uni.removeStorageSync(that.search_history_key)
							that.history_list = []

						}
					}
				})

			},
			//搜索
			search(e, item) {

				if (!item) {
					if (!this.keyword) {
						this.keyword = this.placeholder
					}
					item = this.keyword
				} else {
					this.keyword = item
				}


				let that = this

				//历史搜索列表
				uni.getStorage({
					key: this.search_history_key,
					success: (res) => {
						let old_data = JSON.parse(res.data);
						//加入搜索列表
						if (old_data.indexOf(item) !== -1) {
							old_data.splice(old_data.indexOf(item), 1)
						}
						old_data.unshift(item)

						if (old_data.length > 10) {
							old_data.pop()
						}

						uni.setStorage({
							key: this.search_history_key,
							data: JSON.stringify(old_data)
						});

					},
					fail: (e) => {

						uni.setStorage({
							key: this.search_history_key,
							data: JSON.stringify([item])
						});
					}
				});
				
				//存储搜索状态
				uni.setStorage({
					key: 'search_num_time',
					data: 1
				});
				
				
				//前往搜索结果页面
				// #ifdef H5
				this.$util.to('/pages/search/searchList?keyword=' + encodeURIComponent(item))
				// #endif
				// #ifdef MP
				this.$util.to('/pages/search/searchList?keyword=' + item)
				// #endif
				


			},
			//输入
			onKeyInput(e) {
			
				if(e.target.value==''){
					this.query_list = []
				}else{
					this.querySearch()
				}
			},
			//商品名称列表
			querySearch() {
				//热门搜索
				this.$u.api.querySearch({
					keyword:this.keyword
				}).then(res => {
					this.query_list = res
				}).catch(res => {})
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	

	
	.navitionBar {
		height: 82rpx;
		display: flex;
		align-items: center;
		position: relative;
		padding: 0rpx 20rpx;
		box-sizing: border-box;
		background: #fafafa;
	}
	page {
		height: 100%;
		margin: 0;
		padding: 0;
		background: #f7f7f7;
	}

	.hasBg {
		background-color: #fff;
	}

	.navitionBar .backArea {
		width: 58rpx;
		height: 58rpx;
	}

	.navitionBar .backArea .headerBack {
		width: 58rpx;
		height: 58rpx;
	}

	.navitionBar .navTitle {
		font-size: 32rpx;
		color: #1a1a1a;
		flex: 1;
		text-align: center;
		margin-left: -84rpx;
	}

	.fullBody {
		position: relative;
		box-sizing: border-box;
		height: 100%;
		display: flex;
		flex-direction: column;
		background: #f7f7f7;
	}

	.fullBody .flexScroll {
		position: relative;
		overflow: scroll;
		flex: 1;
		background: #f7f7f7;
	}


	.searchWrap {
		position: relative;
		font-size: 0;
		height: 92rpx;
		display: flex;
		flex-direction: row;
		padding-left: 32rpx;
		align-items: center;
		box-sizing: border-box;
		background: #fff;
		display: flex;
		align-items: center;
		justify-content: center;
	}

	.searchWrap .inputWrap {
		position: relative;
		flex: 1;
		width: auto;
		height: 64rpx;
		background: #f3f3f3;
		display: flex;
		align-items: center;
		border-radius: 32rpx;
	}

	.searchWrap .inputWrap .iconWrap {
		position: absolute;
		top: 50%;
	}

	.searchWrap .inputWrap .inputText {
		font-size: 22rpx;
		color: #000;
		padding: 0 80rpx;
		width: 100%;
	}

	.searchWrap .inputWrap .iconWrap.search {
		left: 24rpx;
		width: 40rpx;
		height: 40rpx;
		margin-top: -20rpx;
	}

	.searchWrap .inputWrap .iconWrap.clear {
		right: 20rpx;
		width: 22rpx;
		height: 22rpx;
		margin-top: -10rpx;
	}

	.searchWrap .inputWrap .iconWrap .img {
		width: 100%;
		height: 100%;
	}

	.searchWrap .searchTxt {
		display: flex;
		align-items: center;
		justify-content: center;
		flex: 0 0 82rpx;
		font-size: 30rpx;
		color: #000;
	}

	.searchTip {
		position: absolute;
		left: 0;
		width: 100%;
		top: 0;
		height: 100%;
		box-sizing: border-box;
		z-index: 3;
		background: #fff;
	}
	.searchTip .tipWrap{
		    padding-left: 32rpx;
		    background: #fff;
		}
	.searchTip .tip {
	    display: flex;
	    width: 100%;
	    font-size: 28rpx;
	    color: #000;
	    padding: 26rpx 32rpx 26rpx 0;
	    border-bottom: 1rpx solid #e0e0e0;
	    background: #fff;
	}
	.searchWords {
		font-size: 0;
		padding: 32rpx;
		margin-bottom: 12rpx;
		background: #fff;
	}

	.searchWords .tit {
		position: relative;
		font-size: 28rpx;
		color: #000;
		margin-bottom: 6rpx;
	}

	.searchWords .tit .clear {
		position: absolute;
		width: 30rpx;
		height: 28rpx;
		right: 0;
		top: 0;
	}

	.searchWords .tit .clear .img {
		width: 100%;
		height: 100%;
	}

	.searchWords .wordWrap {
		display: flex;
		align-items: center;
		box-sizing: border-box;
		font-size: 0;
		flex-wrap: wrap;
	}

	.searchWords .wordWrap .word {
		overflow: hidden;
		text-overflow: ellipsis;
		white-space: nowrap;
		max-width: 100%;
		font-size: 22rpx;
		line-height: 22rpx;
		padding: 10rpx 22rpx;
		color: #000;
		margin: 22rpx 26rpx 0 0;
		border-radius: 8rpx;
		background: #f9f9f9;
		box-sizing: border-box;
	}

	.searchWords .wordWrap .word .iconTag {
		display: inline-block;
		margin-left: 6rpx;
		width: 26rpx;
		height: 26rpx;
	}

	.searchWords .wordWrap .word .iconTag .img {
		width: 100%;
		height: 100%;
	}
	
	.img{
		width: 100%;
		height: 100%;
	}
</style>
